        ("b", "c"),
        ("c", "d"),
    ]


def test_sliding_window_with_generator():
    gen = (x for x in range(5))

    assert list(sliding_window(gen, 2)) == [
        (0, 1),
        (1, 2),
        (2, 3),
        (3, 4),
    ]


def test_sliding_window_size_one():
