def test_sliding_window_is_lazy_after_initial_window():
    consumed = []

    def gen():
        for x in range(5):
            consumed.append(x)
            yield x

    windows = sliding_window(gen(), 3)

    assert next(windows) == (0, 1, 2)
    assert consumed == [0, 1, 2]

    assert next(windows) == (1, 2, 3)
    assert consumed == [0, 1, 2, 3]
